def gen(rng, size):
    cap = rng.randint(1, 8)
    ops = ['LRUCache']
    args = [[cap]]
    for _ in range(max(1, size)):
        if rng.random() < 0.5:
            ops.append('put'); args.append([rng.randint(0, 20), rng.randint(0, 1000)])
        else:
            ops.append('get'); args.append([rng.randint(0, 20)])
    return [ops, args]

