class LRUCache {
    constructor(capacity) {
        this.cap = capacity;
        this.m = new Map();
    }
    get(key) {
        if (!this.m.has(key)) return -1;
        const v = this.m.get(key);
        this.m.delete(key);
        this.m.set(key, v);
        return v;
    }
    put(key, value) {
        if (this.m.has(key)) this.m.delete(key);
        this.m.set(key, value);
        if (this.m.size > this.cap) {
            this.m.delete(this.m.keys().next().value);
        }
    }
}
